#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX 100
int main() {
    int n;
    scanf("%d", &n);
    char s[n][MAX];
    for (int i = 0; i < n; i++) {
        scanf("%s", s[i]);
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        int flag = 0;
        for (int j = 0; j < i; j++) {
            if (strcmp(s[i], s[j]) == 0) {
                flag = 1;
                break;
            }
        }
        if (flag == 0) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

